webpackJsonp([40422688436078],{517:function(t,e){t.exports={data:{site:{siteMetadata:{title:"Jeffry.in",author:"Jeff Wainwright"}},markdownRemark:{id:"/Users/jwainwright/Dropbox/me/git-docs/yowainwright.github.io/src/pages/2017-05-22-week-19-17.md absPath of file >>> MarkdownRemark",html:'<p><strong>From Instagram:</strong> My two favorite peaks in Angeles Forest, Mt Disappointment &#x26; Mt Deception, have interesting literal histories—their naming is the result of a mistake. Despite their mislabeling, they stand; formidable &#x26; beautiful. On the day of this photo, because of fog and snow, all signs of humanity were lost yet the mountains remained solid. Labels don’t mean much to mountains. I want to be like a mountain! </p>\n<figure>\n  <img src="https://yowainwright.imgix.net/wk-19/snow-mountains.jpg?w=800&h=800&crop=focalpoint&auto=format" alt="Mount Disappointment" />\n</figure>',frontmatter:{featured_image:"https://yowainwright.imgix.net/wk-19/snow-mountains.jpg",meta:"Week 19, mislabeled mountains and other things I enjoy.",title:"Week 19, mislabeled mountains and other things I enjoy",date:"May 22, 2017",path:"/week-19-17/"}}},pathContext:{}}}});
